#include<bits/stdc++.h>
using namespace std;

int main()
{
	int a,b,c,d,maxn,mina;
	scanf("%d%d%d",&a,&b,&c);
	maxn=a;
	if(b>maxn)
	maxn=b;
	if(c>maxn)
	maxn=c;

	mina=a;
	if(b<mina)
	mina=b;
	if(c<mina)
	mina=c;
	for(int i=mina;i>=1;i--)
	{
		if((maxn%i==0)&&(mina%i==0))
		{
			d=i;
			break;
		}
	}
	maxn=maxn/d;
	mina=mina/d;
	printf("%d",mina);
	printf("/");
	printf("%d",maxn);
	return 0;
}
